var e=[{id:`L2_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`함선의 상황은?`,JPN:`艦船の状況は？`,ENG:`How's our ship doing?`,TWN:`艦船的情況如何？`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`3번 보조 동력기관 작동 불가!`,JPN:`3番補助動力機関作動不可！`,ENG:`Its third auxiliary engine isn't working anymore.`,TWN:`3號輔助動力機無法運作！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`함선 무장 8할 소실! 다음 공격은 요격이 불가능합니다!`,JPN:`艦船武装8割消失！　次の攻撃は迎撃できません！`,ENG:`It's lost eighty percent of its armament. We can't intercept any more attacks!`,TWN:`艦船武裝有8成毀損！無法攔截下一次的攻擊！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`역시…… 연합 함대가 상대했을 때보다 더 강해졌어. `,JPN:`やはり……連合艦隊が相手した時よりもさらに強くなっている。`,ENG:`I knew it... It's gotten stronger since it fought the Coalition Fleet. `,TWN:`果然……比那時候和聯合艦隊交手時變強許多！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`급조한 부품으로 어떻게 저만큼 성능을 향상시켰지? 정말로 기계가 진화라도 하는 건가?`,JPN:`急造した部品でどうやってあんなに性能を向上させられた？　本当に機械が進化でもするのか？`,ENG:`How did they improve its performance so much with improvised components? Can that machine really evolve?`,TWN:`是怎麼用粗製濫造的零件，把性能提升到這個程度的？真的是機械進化嗎？`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`실장님! 마지막 호위함도 당했습니다! 이 이상은 위험합니다!`,JPN:`室長！　最後の護衛艦もやられました！　これ以上は危険です！`,ENG:`Chief! Our last escort ship went down! We're too vulnerable right now!`,TWN:`室長！最後一艘護衛艦也快不行了！這樣下去會有危險！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`이런……`,JPN:`そんな……`,ENG:`Oh, no...`,TWN:`可惡……`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`선원들을 모두 대피시키세요! 함선은 포기합니다!`,JPN:`船員たちを全員避難させてください！　艦船は諦めます！`,ENG:`Evacuate everyone! We'll give up the ship!`,TWN:`全員撤退！放棄艦船！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`제 2파가 옵니다!`,JPN:`第二波が来ます！`,ENG:`Here comes the second wave!`,TWN:`第2波來了！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`방금 뭐였죠?`,JPN:`今のは何でしょう？`,ENG:`What was that?`,TWN:`剛剛是怎麼回事？`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`어서 상황 보고하세요!`,JPN:`すみやかに状況を報告してください！`,ENG:`Come on, tell me!`,TWN:`立刻報告現況！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`놈이 기동을 멈췄습니다!`,JPN:`奴の起動が止まりました！`,ENG:`The robot stopped moving!`,TWN:`那傢伙停止運作了！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`특수탄의 전자기 펄스를 직격으로 맞았어요!`,JPN:`特殊弾の電磁パルスが直撃しました！`,ENG:`It was hit by EMP from a special bullet!`,TWN:`特殊彈的電磁脈衝正中紅心！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`네? 그렇다는 건……?`,JPN:`え？　それはつまり……？`,ENG:`What? That means...`,TWN:`嗯？那就表示……？`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`<color=#ffd34c>휴우, 아슬아슬했네요.</color>`,JPN:`<color=#ffd34c>ふう、ギリギリでしたね。</color>`,ENG:`<color=#ffd34c>Whew, that was close.</color>`,TWN:`<color=#ffd34c>呼…真是驚險呢！</color>`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};